import React from 'react'
import { BrowserRouter as Router, Route, Link } from "react-router-dom";

import HousingAdmin from './HousingAdmin/HousingAdmin';
import PartnerAdmin from './PartnerAdmin/PartnerAdmin';
import AddHousing from "./AddHousing/AddHousing"

class App extends React.Component{
    render() {
        return(
            <Router>
                <div>
                    <nav>
                        <ul>
                            <li>
                                <Link to="/">Housing Admin Panel</Link>
                            </li>
                            <li>
                                <Link to="/partners/">Partners Admin Panel</Link>
                            </li>
                        </ul>
                    </nav>
                    <ul>
                        <li>
                            <Link to="/add_housing/">Add Housing</Link>
                        </li>
                    </ul>
                    <Route path="/" exact component={HousingAdmin} />
                    <Route path="/partners/" component={PartnerAdmin} />
                    <Route path="/add_housing/" component={AddHousing}/>
                </div>
            </Router>
        );
    }
}

export default App;
