import React from 'react'
import algoliasearch from 'algoliasearch';
import { InstantSearch, SearchBox, Hits, Pagination, connectHits } from 'react-instantsearch-dom';
import { BrowserRouter as Router, Route, Link } from "react-router-dom";

const searchClient = algoliasearch('0HAV8OIN0H', 'e43a69fc7d9c3607d9a4e677c8b250dd');

const hits = ({ hits }) => (
    <ol>
        {hits.map(hit => (
            <li key={hit.objectID}>{hit.name}</li>
        ))}
    </ol>
);

const CustomHits = connectHits(hits);

class PartnerAdmin extends React.Component{
    constructor(props){
        super(props);
    }
    render() {
        return (
            <InstantSearch searchClient={searchClient} indexName="Partners">
                <SearchBox />
                <CustomHits />
                <Pagination/>
            </InstantSearch>
        );
    }
}

export default PartnerAdmin;
