import React from 'react'
import algoliasearch from "algoliasearch";

import "./AddHousing.css";

const stateAbbreviations = [
    'AL','AK','AS','AZ','AR','CA','CO','CT','DE','DC','FM','FL','GA',
    'GU','HI','ID','IL','IN','IA','KS','KY','LA','ME','MH','MD','MA',
    'MI','MN','MS','MO','MT','NE','NV','NH','NJ','NM','NY','NC','ND',
    'MP','OH','OK','OR','PW','PA','PR','RI','SC','SD','TN','TX','UT',
    'VT','VI','VA','WA','WV','WI','WY'
];

class AddHousing extends React.Component{
    constructor(props){
        super(props);
        this.handleChange = this.handleChange.bind(this);
        this.add = this.add.bind(this);
        this.state = {
            data: [{
                "property_name": "",
                "contact_name": "",
                "phone": "",
                "email": "",
                "address":{
                    "street": "",
                    "city": "",
                    "state": "",
                    "zip": ""
                },
                "pet_policy": "",
                "website": "",
                "_show": false,
                "_geoloc": {
                    "lat" : '',
                    "lng": ''
                }
            }],
            items: [],
            error: null,
            isLoaded: false,
        };
    }
    handleChange (event) {
        if(event.target.name === "street" ||
            event.target.name === "city" ||
            event.target.name === "state" ||
            event.target.name === "zip"
        ) this.state.data[0].address[event.target.name] = event.target.value;
        else this.state.data[0][event.target.name] = event.target.value;
        this.state.data[0]._show = event.target.checked;
        let address = this.state.data[0].address.street.replace(/ /g, '+');
        let city = this.state.data[0].address.city.replace(/ /g, '+');
        this.setState({
            address: address,
            city: city
        });
    }
    add(e) {
        e.preventDefault();

        // const status = document.querySelector(".status");
        // status.querySelector("p").innerHTML = "Record is added";
        // status.style = `background: #d4edda`;
        // status.querySelector("p").style = `color: #155724`;
        // status.classList.add('show');
        // setTimeout(()=>{
        //     status.classList.remove('show');
        // }, 1000);

        console.log(this.state.data[0]);

        fetch(`https://locationiq.org/v1/search.php?key=e0860999ab60bf&q=${this.state.address}%2C+${this.state.city}%2C+${this.state.data[0].address.state}+${this.state.data[0].stateCode}%2C+USA&format=json`)
            .then(res => res.json())
            .then(
                (result) => {
                    this.setState({
                        isLoaded: true
                    });
                    this.state.data[0]._geoloc.lat = parseFloat(result[0].lat);
                    this.state.data[0]._geoloc.lng = parseFloat(result[0].lon);

                    setTimeout(()=>{

                        var client = algoliasearch('0HAV8OIN0H', '2a6b7c4e8ea2f852da8e0edb478f9c4a');
                        var index = client.initIndex('Housing');
                        index.addObjects(this.state.data, function(err, content) {
                            const status = document.querySelector(".status");
                            if (err) {
                                status.querySelector("p").style = `color: #721c24`;
                                status.style = `background: #f8d7da`;
                            }
                            status.querySelector("p").innerHTML = "Record is added";
                            status.style = `background: #d4edda`;
                            status.querySelector("p").style = `color: #155724`;
                            status.classList.add('show');
                            setTimeout(()=>{
                                status.classList.remove('show');
                            }, 1000);
                        });
                    }, 500)
                },
                (error) => {
                    this.setState({
                        isLoaded: true,
                        error
                    });
                }
            )
    }
    render() {
        return (
            <div className="add-housing">
                <div className="status"><p></p></div>
                <h2>Add new Housing</h2>
                <form onSubmit={this.add}>
                    <div className="inputs">
                        <input name="property_name" onChange={event => this.handleChange(event)} placeholder="property name"/>
                        <input name="contact_name" onChange={event => this.handleChange(event)} placeholder="contact name"/>
                        <input name="phone" onChange={event => this.handleChange(event)} placeholder="contact number"/>
                        <input name="email" type="mail" onChange={event => this.handleChange(event)} placeholder="contact email"/>
                        <input name="street" onChange={event => this.handleChange(event)} placeholder="street address"/>
                        <input name="city" onChange={event => this.handleChange(event)} placeholder="city"/>
                        {/*<input name="state" onChange={event => this.handleChange(event)} placeholder="state"/>*/}
                        <select name="state" onChange={event => this.handleChange(event)}>
                            <option>Sate</option>
                            {stateAbbreviations.map(item=>(
                                <option key={item} value={item}>{item}</option>
                            ))}
                        </select>
                        <input name="zip" onChange={event => this.handleChange(event)} placeholder="zip"/>
                        <textarea name="pet_policy" onChange={event => this.handleChange(event)} placeholder="pet Policy Status"/>
                        <input name="website" onChange={event => this.handleChange(event)} placeholder="website"/>
                    </div>
                    <span>Show on website</span>
                    <br/>
                    <label className="switch">
                        <input
                            name="_show"
                            type="checkbox"
                            checked={this.state.showOnWebsite}
                            onChange={event => this.handleChange(event)} />
                        <span className="slider round"></span>
                    </label>
                    <button type="submit" onClick={this.add}>Add</button>
                </form>
            </div>
        );
    }
}

export default AddHousing;
